class.description:
Dynamically routes, isolates, and terminates background tasks asynchronously globally. It handles basic routing safely avoiding blocking UI components strictly natively mapping hooks.
[codeblock]
var manager = JustAMCPTaskManager.new()
manager.create_task("task_001", 100000)

var gt = manager.get_task("task_001")
print(gt["status"]) # working

manager.complete_task("task_001", {"content": [{"type": "text", "text": "Task Completed"}]})

var cx = manager.create_task("task_cancel", 900)
manager.cancel_task("task_cancel")
[/codeblock]
